import{_ as s,o as t,c as a,a2 as e}from"./chunks/framework.m9rfQn3T.js";const k=JSON.parse('{"title":"git合并冲突","description":"","frontmatter":{"title":"git合并冲突","date":"2026-01-09T11:35:41.000Z","permalink":"/pages/ff2bcdf4880ff8/","categories":["笔记","工作笔记"],"tags":[null]},"headers":[],"relativePath":"20.笔记/00.工作笔记/06.git合并冲突.md","filePath":"20.笔记/00.工作笔记/06.git合并冲突.md","lastUpdated":1782538095000}'),n={name:"20.笔记/00.工作笔记/06.git合并冲突.md"};function l(o,i,h,r,d,g){return t(),a("div",null,[...i[0]||(i[0]=[e(`<p>开发的时候总是有人反向合并，但是那个人却感觉他没合并错误，查找之后发现是 gitlab 的锅，也就是 gitlab 线上合并会导致把 dev 分支的代码拉回到特性分支</p><p>GitLab 在线上解决冲突时出现“两个分支同步最新合并后代码”的现象，本质是其 <strong>冲突解决机制的设计差异</strong> 导致的，与本地 <code>git merge</code> 的行为逻辑不同。以下是详细分析及解决方案：</p><hr><h2 id="⚙️-1-gitlab-线上解决冲突的机制" tabindex="-1">⚙️ <strong>1. GitLab 线上解决冲突的机制</strong> <a class="header-anchor" href="#⚙️-1-gitlab-线上解决冲突的机制" aria-label="Permalink to &quot;⚙️ **1. GitLab 线上解决冲突的机制**&quot;">​</a></h2><p>当你在 GitLab Web 界面点击 <strong>&quot;Resolve conflicts&quot;</strong> 时，系统会执行以下操作：</p><ul><li><strong>自动创建合并提交</strong>：GitLab <strong>直接在源分支（如 <code>fix</code>）上生成一个包含冲突解决方案的新提交</strong>，并将目标分支（如 <code>dev</code>）的最新内容合并到源分支中（[2] [3] [11]）。</li><li><strong>同步目标分支代码</strong>：为解决冲突，GitLab 必须将 <code>dev</code> 的最新代码拉取到 <code>fix</code> 分支，否则无法对比冲突点（[9] [15]）。</li><li><strong>结果</strong>：<code>fix</code> 分支被更新为包含 <code>dev</code> 分支最新代码的版本，导致 <code>fix</code> 分支“污染”（即包含非本分支的代码）。</li></ul><blockquote><p>💡 <strong>设计原因</strong>：GitLab 的在线冲突解决是为快速处理简单冲突设计的，<strong>依赖源分支直接提交解决方案</strong>，而非像本地操作那样在目标分支生成合并提交（[3] [13]）。</p></blockquote><hr><h2 id="🔄-2-本地-git-merge-与-gitlab-的差异" tabindex="-1">🔄 <strong>2. 本地 <code>git merge</code> 与 GitLab 的差异</strong> <a class="header-anchor" href="#🔄-2-本地-git-merge-与-gitlab-的差异" aria-label="Permalink to &quot;🔄 **2. 本地 \`git merge\` 与 GitLab 的差异**&quot;">​</a></h2><p>本地合并的流程完全不同：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">         # 切换到目标分支</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">            # 合并特性分支</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 出现冲突时手动解决</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">                # 标记冲突已解决</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Merge fix into dev&quot;</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">  # 提交到目标分支（dev）</span></span></code></pre></div><ul><li><strong>结果</strong>：冲突解决方案仅提交到 <code>dev</code> 分支，<code>fix</code> 分支保持原状（[16] [19]）。</li></ul><hr><h2 id="⚠️-3-为何不符合开发规范" tabindex="-1">⚠️ <strong>3. 为何不符合开发规范？</strong> <a class="header-anchor" href="#⚠️-3-为何不符合开发规范" aria-label="Permalink to &quot;⚠️ **3. 为何不符合开发规范？**&quot;">​</a></h2><p>用户提到的 <strong>“dev 分支很脏”</strong> 问题核心在于：</p><ol><li><strong>分支职责混乱</strong>：<code>fix</code> 分支作为特性分支，应仅包含本功能代码。但 GitLab 的解决方式导致其混入 <code>dev</code> 的无关代码，破坏分支隔离性（[6] [10]）。</li><li><strong>污染风险</strong>：若 <code>dev</code> 分支存在未测试代码，同步到 <code>fix</code> 分支可能引入新缺陷（[6] [14]）。</li><li><strong>历史记录混乱</strong>：<code>fix</code> 分支的提交历史包含合并提交，干扰代码追溯（[17]）。</li></ol><hr><h2 id="🛠️-4-解决方案-规范操作流程" tabindex="-1">🛠️ <strong>4. 解决方案：规范操作流程</strong> <a class="header-anchor" href="#🛠️-4-解决方案-规范操作流程" aria-label="Permalink to &quot;🛠️ **4. 解决方案：规范操作流程**&quot;">​</a></h2><h3 id="✅-推荐方案-本地解决冲突-符合-git-标准流程" tabindex="-1">✅ 推荐方案：本地解决冲突（符合 Git 标准流程） <a class="header-anchor" href="#✅-推荐方案-本地解决冲突-符合-git-标准流程" aria-label="Permalink to &quot;✅ 推荐方案：本地解决冲突（符合 Git 标准流程）&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 在特性分支（fix）上操作</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> checkout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fetch</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">          # 获取远程最新状态</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> merge</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin/dev</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">      # 将 dev 合并到 fix（触发冲突）</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 手动解决冲突，保留所需代码</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Resolve conflicts with dev&quot;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> fix</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">       # 更新远程 fix 分支</span></span></code></pre></div><ul><li><strong>优点</strong>：冲突解决方案仅提交到 <code>fix</code> 分支，<code>dev</code> 分支保持纯净（[15] [19]）。</li><li><strong>后续操作</strong>：在 GitLab 重新发起合并请求（MR），此时无冲突可直接合并（[5] [12]）。</li></ul><h3 id="⚠️-规避-gitlab-在线解决-复杂场景" tabindex="-1">⚠️ 规避 GitLab 在线解决（复杂场景） <a class="header-anchor" href="#⚠️-规避-gitlab-在线解决-复杂场景" aria-label="Permalink to &quot;⚠️ 规避 GitLab 在线解决（复杂场景）&quot;">​</a></h3><p>若坚持使用在线工具，需注意：</p><ol><li>仅适用于<strong>文本冲突且改动简单</strong>的场景（[2]）。</li><li>解决后立即基于 <code>fix</code> 分支测试，避免污染代码影响功能（[6]）。</li></ol><hr><h2 id="💎-5-设计矛盾的本质" tabindex="-1">💎 <strong>5. 设计矛盾的本质</strong> <a class="header-anchor" href="#💎-5-设计矛盾的本质" aria-label="Permalink to &quot;💎 **5. 设计矛盾的本质**&quot;">​</a></h2><p>GitLab 的在线冲突解决是<strong>为简化流程设计的快捷工具</strong>，但违背了 Git 分支管理的核心原则：</p><ul><li><strong>理想状态</strong>：合并时目标分支（<code>dev</code>）应单向集成源分支（<code>fix</code>）的变更，而非反向同步（[10] [17]）。</li><li><strong>妥协点</strong>：在线工具牺牲分支纯洁性换取操作便捷性，<strong>适合小团队或紧急修复</strong>（[11] [13]）。</li></ul><hr><h2 id="📌-总结建议" tabindex="-1">📌 <strong>总结建议</strong> <a class="header-anchor" href="#📌-总结建议" aria-label="Permalink to &quot;📌 **总结建议**&quot;">​</a></h2><table tabindex="0"><thead><tr><th><strong>场景</strong></th><th><strong>操作方式</strong></th><th><strong>分支清洁度</strong></th></tr></thead><tbody><tr><td>规范开发</td><td>本地解决冲突</td><td>✅ 源/目标分支均纯净</td></tr><tr><td>简单冲突快速处理</td><td>GitLab 在线解决</td><td>⚠️ 源分支被污染</td></tr></tbody></table><p><strong>最佳实践</strong>：</p><ol><li><strong>始终本地解决冲突</strong>，通过 <code>git merge</code> 或 IDE 工具（如 VS Code/GitKraken）操作（[18] [19]）。</li><li>合并前更新分支：确保 <code>fix</code> 分支基于 <code>dev</code> 的最新提交开发，减少冲突概率（[12] [14]）。</li><li>复杂项目推荐 <strong>GitFlow 分支模型</strong>，通过 <code>release</code> 分支隔离开发与集成交付（[6]）。</li></ol><blockquote><p>通过回归本地操作，可彻底避免分支污染问题，确保 <code>dev</code> 仅包含合并后的完整功能，而非开发中的中间状态（[6] [10]）。</p></blockquote>`,34)])])}const c=s(n,[["render",l]]);export{k as __pageData,c as default};
